mapper.select:
SELECT g.gallery_seq ,g.title ,g.gallery_year ,g.description ,g.file_seq ,g.sort_seq ,g.use_yn ,cu.name AS rgst_user_name ,g.created_at AS rgst_date_time ,uu.name AS upt_user_name ,g.updated_at AS upt_date_time ,COALESCE(img.image_count, 0) AS image_count ,img.cover_file_dtl_seq ,img.cover_file_path FROM event.gallery g LEFT JOIN event.users cu ON cu.user_seq = g.created_by LEFT JOIN event.users uu ON uu.user_seq = g.updated_by LEFT JOIN LATERAL ( SELECT COUNT(*)::integer AS image_count ,( ARRAY_AGG(d.file_dtl_seq ORDER BY d.sort_seq ASC, d.file_dtl_seq ASC) )[1] AS cover_file_dtl_seq ,( ARRAY_AGG(d.file_path ORDER BY d.sort_seq ASC, d.file_dtl_seq ASC) )[1] AS cover_file_path FROM event.tb_file_dtl d WHERE d.file_seq = g.file_seq AND d.del_yn = 'N' AND LOWER(COALESCE(d.file_type, '')) IN ('jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp') ) img ON TRUE
g.deleted_at IS NULL
AND g.gallery_year = #{galleryYear}
AND g.use_yn = #{useYn}
AND ( g.title ILIKE '%' || #{keyword} || '%' OR g.description ILIKE '%' || #{keyword} || '%' )
ORDER BY g.gallery_year DESC, g.sort_seq ASC, g.gallery_seq DESC

mapper.update:
UPDATE event.gallery
SET  title = #{title}
    ,gallery_year = #{galleryYear}
    ,description = #{description,jdbcType=VARCHAR}
    ,file_seq = #{fileSeq,jdbcType=BIGINT}
    ,sort_seq = COALESCE(#{sortSeq,jdbcType=INTEGER}, 0)
    ,use_yn = COALESCE(#{useYn,jdbcType=CHAR}, use_yn)
    ,updated_by = #{uptUserSeq,jdbcType=BIGINT}
    ,updated_at = CURRENT_TIMESTAMP
WHERE gallery_seq = #{gallerySeq}
  AND deleted_at IS NULL

UPDATE event.gallery
SET  deleted_at = CURRENT_TIMESTAMP
    ,updated_by = #{uptUserSeq,jdbcType=BIGINT}
    ,updated_at = CURRENT_TIMESTAMP
WHERE gallery_seq = #{gallerySeq}
  AND deleted_at IS NULL
